CREATE FUNCTION public.check_vp(p_makho character varying DEFAULT NULL::character varying) RETURNS TABLE(mavp character varying, tenvp character varying, soluong integer, makho character varying, tenkho character varying, diachi character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT vp.mavp, vp.tenvp, vp.soluong, k.makho, k.tenkho, k.diachi
    FROM vatpham vp JOIN kho k ON k.makho = vp.makho
    WHERE vp.soluong < 50
      AND (p_makho IS NULL OR vp.makho = p_makho)
    ORDER BY vp.soluong ASC;
END;
$$;


--
-- Name: ds_luong_theo_thang(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ds_luong_theo_thang(p_thang integer, p_nam integer DEFAULT (EXTRACT(year FROM CURRENT_DATE))::integer) RETURNS TABLE(manv character varying, tennv character varying, so_ca bigint, hesoluong double precision, nghi_som bigint, tong_luong numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_thang < 1 OR p_thang > 12 THEN
        RAISE EXCEPTION 'Thang khong hop le: %', p_thang;
    END IF;
    IF p_nam > EXTRACT(YEAR FROM CURRENT_DATE)
        OR (p_nam = EXTRACT(YEAR FROM CURRENT_DATE)
            AND p_thang >= EXTRACT(MONTH FROM CURRENT_DATE)) THEN
        RAISE EXCEPTION 'Chi duoc xem luong thang da qua.';
    END IF;

    RETURN QUERY
    SELECT
        nv.manv, nv.tennv,
        COUNT(dl.ngay)::BIGINT AS so_ca,
        nv.hesoluong,
        COUNT(CASE WHEN cl.nghisom THEN 1 END)::BIGINT AS nghi_som,
        SUM(
            CASE WHEN cl.nghisom
                THEN nv.hesoluong * 1000000 * 0.8
                ELSE nv.hesoluong * 1000000
            END
        )::NUMERIC AS tong_luong
    FROM nhanvien nv
    LEFT JOIN dilam dl ON nv.manv = dl.manv
        AND EXTRACT(MONTH FROM dl.ngay) = p_thang
        AND EXTRACT(YEAR  FROM dl.ngay) = p_nam
    LEFT JOIN calam cl ON dl.ngay = cl.ngay AND dl.cathu = cl.cathu
    GROUP BY nv.manv, nv.tennv, nv.hesoluong
    ORDER BY tong_luong DESC NULLS LAST;
END;
$$;


--
-- Name: fn_cap_nhat_calam_status(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_cap_nhat_calam_status() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_ngay  DATE;
  v_cathu VARCHAR(10);
  v_so_nv INTEGER;
BEGIN
  v_ngay  := COALESCE(NEW.ngay,  OLD.ngay);
  v_cathu := COALESCE(NEW.cathu, OLD.cathu);
  SELECT COUNT(*) INTO v_so_nv FROM dilam WHERE ngay = v_ngay AND cathu = v_cathu;
  UPDATE calam SET status = CASE
    WHEN v_so_nv >= 3 THEN 'Du nguoi'
    WHEN v_so_nv > 0  THEN 'Thieu nguoi'
    ELSE                   'Chua co nguoi'
  END WHERE ngay = v_ngay AND cathu = v_cathu;
  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: fn_cap_nhat_trang_thai_phong(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_cap_nhat_trang_thai_phong() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Bắt đầu sử dụng
    IF NEW.status = 'Dang dung' AND OLD.status != 'Dang dung' THEN
        PERFORM fn_dat_cho(NEW.maghe, NEW.mapr);

    -- Đang dùng nhưng đổi ghế/phòng
    ELSIF NEW.status = 'Dang dung' AND OLD.status = 'Dang dung' THEN
        IF OLD.maghe IS DISTINCT FROM NEW.maghe THEN
            PERFORM fn_tra_cho(OLD.maghe, NULL);
            PERFORM fn_dat_cho(NEW.maghe, NULL);
        END IF;
        IF OLD.mapr IS DISTINCT FROM NEW.mapr THEN
            PERFORM fn_tra_cho(NULL, OLD.mapr);
            PERFORM fn_dat_cho(NULL, NEW.mapr);
        END IF;

    -- Kết thúc hoặc hủy
    ELSIF NEW.status IN ('Hoan thanh', 'Da huy') AND OLD.status = 'Dang dung' THEN
        PERFORM fn_tra_cho(NEW.maghe, NEW.mapr);
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: fn_check_ca_day(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_check_ca_day() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE v_so_nv INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_so_nv FROM dilam
  WHERE ngay = NEW.ngay AND cathu = NEW.cathu;
  IF v_so_nv >= 3 THEN
    RAISE EXCEPTION 'Ca % ngay % da du 3 nhan vien.', NEW.cathu, NEW.ngay;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: fn_check_chitietorder_status(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_check_chitietorder_status() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE v_status VARCHAR(20);
BEGIN
  SELECT status INTO v_status FROM orders WHERE maorder = NEW.maorder;
  IF v_status IN ('Hoan thanh', 'Da huy') THEN
    RAISE EXCEPTION 'Khong the them/sua vat pham: order % da %.', NEW.maorder, v_status;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: fn_checkin(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_checkin(p_maorder character varying) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_status      VARCHAR(20);
  v_thoigiandat TIMESTAMP;
BEGIN
  SELECT status, thoigiandat INTO v_status, v_thoigiandat
  FROM orders WHERE maorder = p_maorder;

  IF NOT FOUND THEN                              -- FIX: thêm check này
    RAISE EXCEPTION 'Order % khong ton tai.', p_maorder;
  END IF;

  IF v_status != 'Dat truoc' THEN
    RAISE EXCEPTION 'Order khong phai Dat truoc (hien tai: %).', v_status;
  END IF;

  IF NOW() > v_thoigiandat + INTERVAL '30 minutes' THEN
    UPDATE orders SET status = 'Da huy' WHERE maorder = p_maorder;
    RETURN 'Order ' || p_maorder || ' bi huy tu dong (qua 30 phut).';
  END IF;

  UPDATE orders SET status = 'Dang dung', giobatdau = NOW()
  WHERE maorder = p_maorder;

  RETURN 'Check-in thanh cong. Bat dau su dung.';
END;
$$;


--
-- Name: fn_dat_cho(character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_dat_cho(p_maghe character varying, p_mapr character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE v_mapc VARCHAR(6);
BEGIN
    IF p_maghe IS NOT NULL THEN
        SELECT mapc INTO v_mapc FROM ghe WHERE maghe = p_maghe;
        UPDATE phongchung SET soghetrong = soghetrong - 1 WHERE mapc = v_mapc;
        UPDATE phongchung SET status = 'Day' WHERE mapc = v_mapc AND soghetrong = 0;
    END IF;
    IF p_mapr IS NOT NULL THEN
        UPDATE phongrieng SET status = 'Day' WHERE mapr = p_mapr;
    END IF;
END;
$$;


--
-- Name: fn_dat_truoc(character varying, character varying, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_dat_truoc(p_maorder character varying, p_makh character varying, p_hoten character varying, p_madv character varying, p_maghe character varying DEFAULT NULL::character varying, p_mapr character varying DEFAULT NULL::character varying, p_sdt character varying DEFAULT NULL::character varying) RETURNS text
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_madv IN ('DV03', 'DV04') THEN
        RAISE EXCEPTION 'DV03/DV04 la goi hoat dong. Hay dang ky hoac gia han trong tab Goi, khong tao trong Orders.';
    END IF;

    PERFORM fn_upsert_khachhang(p_makh, p_hoten, p_sdt);
    VALUES (p_maorder,p_makh,p_madv,p_maghe,p_mapr,'Dat truoc',NOW());
    RETURN 'Dat truoc ' || p_maorder || ' thanh cong. Qua 30 phut khong den se bi huy.';
END;
$$;


--
-- Name: fn_doanh_thu(date, integer, integer, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_doanh_thu(p_ngay date DEFAULT NULL::date, p_thang integer DEFAULT NULL::integer, p_nam integer DEFAULT NULL::integer, p_tungay date DEFAULT NULL::date, p_denngay date DEFAULT NULL::date) RETURNS TABLE(so_order bigint, tong_doanh_thu numeric, trung_binh_hd numeric, tong_tu_dv numeric, tong_tu_vp numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_thang IS NOT NULL AND (p_thang < 1 OR p_thang > 12) THEN
        RAISE EXCEPTION 'p_thang (%) phai nam trong khoang 1..12.', p_thang;
    END IF;

    IF p_ngay IS NOT NULL AND (p_tungay IS NOT NULL OR p_denngay IS NOT NULL) THEN
        RAISE EXCEPTION 'Chi chon ngay cu the hoac khoang ngay, khong chon dong thoi.';
    END IF;

    IF p_denngay IS NOT NULL AND p_tungay IS NULL THEN
        RAISE EXCEPTION 'Da nhap p_denngay thi phai nhap p_tungay.';
    END IF;

    IF p_tungay IS NOT NULL THEN
        p_denngay := COALESCE(p_denngay, CURRENT_DATE);

        IF p_tungay > p_denngay THEN
            RAISE EXCEPTION 'p_tungay (%) khong duoc lon hon p_denngay (%).', p_tungay, p_denngay;
        END IF;
    ELSIF p_ngay IS NULL AND p_thang IS NULL AND p_nam IS NULL THEN
        RAISE EXCEPTION 'Phai truyen ngay, thang/nam, nam, hoac khoang ngay.';
    END IF;

    RETURN QUERY
    WITH order_totals AS (
        SELECT
            o.maorder,
            dv.giagoi::numeric AS tien_dv,
            COALESCE(vp_sub.tong_vp, 0)::numeric AS tien_vp
        FROM orders o
        JOIN dichvu dv ON o.madv = dv.madv
        LEFT JOIN (
            SELECT ct.maorder, SUM(vp.giatien::numeric * ct.soluong) AS tong_vp
            FROM chitietorder ct
            JOIN vatpham vp ON ct.mavp = vp.mavp
            GROUP BY ct.maorder
        ) vp_sub ON o.maorder = vp_sub.maorder
        WHERE o.status = 'Hoan thanh'
          AND (
              (
                  p_tungay IS NOT NULL
                  AND DATE(o.thoigiantt) BETWEEN p_tungay AND p_denngay
              )
              OR (
                  p_tungay IS NULL
                  AND (p_ngay  IS NULL OR DATE(o.thoigiantt) = p_ngay)
                  AND (p_thang IS NULL OR EXTRACT(MONTH FROM o.thoigiantt) = p_thang)
                  AND (p_nam   IS NULL OR EXTRACT(YEAR  FROM o.thoigiantt) = p_nam)
              )
          )
    )
    SELECT
        COUNT(*)::bigint,
        COALESCE(SUM(tien_dv + tien_vp), 0),
        COALESCE(AVG(tien_dv + tien_vp), 0),
        COALESCE(SUM(tien_dv), 0),
        COALESCE(SUM(tien_vp), 0)
    FROM order_totals;
END;
$$;


--
-- Name: fn_hieusuat_nhanvien(date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_hieusuat_nhanvien(p_tungay date, p_denngay date) RETURNS TABLE(ma_nv character varying, ten_nv character varying, so_luong_order bigint, doanh_thu_dich_vu numeric, doanh_thu_vat_pham numeric, tong_doanh_thu numeric)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH doanh_thu_tung_order AS (
        SELECT o.maorder, o.manv,
            COALESCE(dv.giagoi::NUMERIC, 0) AS tien_dv,
            COALESCE(SUM(ct.soluong * vp.giatien::NUMERIC), 0) AS tien_vp
        FROM orders o
        LEFT JOIN dichvu dv ON o.madv = dv.madv
        LEFT JOIN chitietorder ct ON o.maorder = ct.maorder
        LEFT JOIN vatpham vp ON ct.mavp = vp.mavp
        WHERE o.giobatdau::DATE BETWEEN p_tungay AND p_denngay
          AND o.status = 'Hoan thanh'
        GROUP BY o.maorder, o.manv, dv.giagoi
    )
    SELECT nv.manv, nv.tennv::VARCHAR(50),
        COUNT(dto.maorder)::BIGINT,
        SUM(dto.tien_dv)::NUMERIC,
        SUM(dto.tien_vp)::NUMERIC,
        SUM(dto.tien_dv + dto.tien_vp)::NUMERIC
    FROM nhanvien nv
    JOIN doanh_thu_tung_order dto ON nv.manv = dto.manv
    GROUP BY nv.manv, nv.tennv
    ORDER BY tong_doanh_thu DESC;
END;
$$;


--
-- Name: fn_kiem_tra_goi(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_kiem_tra_goi(p_makh character varying) RETURNS boolean
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1 FROM goihoatdong
        WHERE makh = p_makh
          AND status = 'Hoat dong'
          AND ngayketthuc >= CURRENT_DATE
    );
END;
$$;


--
-- Name: fn_kiem_tra_stock(character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_kiem_tra_stock(p_mavp character varying, p_soluong integer) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE v_soluong_kho INT; v_tenvp VARCHAR(20);
BEGIN
    SELECT soluong, tenvp INTO v_soluong_kho, v_tenvp
    FROM vatpham WHERE mavp = p_mavp;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Vat pham % khong ton tai.', p_mavp;
    END IF;
    IF v_soluong_kho < p_soluong THEN
        RAISE EXCEPTION 'Khong du hang. Kho con: % (yeu cau: %).', v_soluong_kho, p_soluong;
    END IF;
    RETURN v_tenvp;
END;
$$;


--
-- Name: fn_nhap_hang(character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_nhap_hang(p_mavp character varying, p_soluong integer) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_makho varchar(6);
    v_tenvp varchar(20);
BEGIN
    IF p_soluong IS NULL OR p_soluong <= 0 THEN
        RAISE EXCEPTION 'So luong nhap phai lon hon 0.';
    END IF;

    UPDATE vatpham
    SET soluong = soluong + p_soluong
    WHERE mavp = p_mavp
    RETURNING makho, tenvp INTO v_makho, v_tenvp;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Vat pham % khong ton tai. Hay tao vat pham truoc.', p_mavp;
    END IF;

    RETURN 'Nhap ' || p_soluong || ' x ' || v_tenvp || ' vao kho ' || v_makho;
END;
$$;


--
-- Name: fn_nhap_hang(character varying, character varying, character varying, numeric, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_nhap_hang(p_makho character varying, p_mavp character varying, p_tenvp character varying, p_giatien numeric, p_soluong integer) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_makho varchar(6);
    v_tenvp varchar(20);
BEGIN
    IF p_soluong IS NULL OR p_soluong <= 0 THEN
        RAISE EXCEPTION 'So luong nhap phai lon hon 0.';
    END IF;

    SELECT makho, tenvp
    INTO v_makho, v_tenvp
    FROM vatpham
    WHERE mavp = p_mavp
    FOR UPDATE;

    IF FOUND THEN
        IF p_makho IS NOT NULL AND p_makho <> v_makho THEN
            RAISE EXCEPTION
                'Vat pham % thuoc kho %, khong the nhap vao kho %.',
                p_mavp, v_makho, p_makho;
        END IF;

        UPDATE vatpham
        SET soluong = soluong + p_soluong
        WHERE mavp = p_mavp;

        RETURN 'Nhap ' || p_soluong || ' x ' || v_tenvp || ' vao kho ' || v_makho;
    END IF;

    IF p_tenvp IS NULL OR trim(p_tenvp) = '' OR p_giatien IS NULL THEN
        RAISE EXCEPTION 'Vat pham moi can co ten va gia tien.';
    END IF;

    VALUES (p_mavp, trim(p_tenvp), p_giatien::money, NULL, p_soluong)
    RETURNING makho INTO v_makho;

    RETURN 'Tao ' || trim(p_tenvp) || ' va nhap ' || p_soluong || ' vao kho ' || v_makho;
END;
$$;


--
-- Name: fn_orders_block_package_service(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_orders_block_package_service() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.madv IN ('DV03', 'DV04') THEN
        RAISE EXCEPTION 'DV03/DV04 la goi hoat dong. Hay dang ky hoac gia han trong tab Goi, khong tao trong Orders.';
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: fn_phat_thuong_vinh_danh(character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_phat_thuong_vinh_danh(p_makh character varying, p_hang integer) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE v_mavp VARCHAR(6); v_tenvp VARCHAR(20);
BEGIN
    IF p_hang <= 5 THEN
        RETURN 'Discount 50,000 VND hoa don tiep theo';

    ELSIF p_hang <= 10 THEN
        SELECT p_makh, 'DV03', CURRENT_DATE, CURRENT_DATE + 1, 'Hoat dong'
        WHERE NOT EXISTS (
            SELECT 1 FROM goihoatdong g WHERE g.makh = p_makh AND g.status = 'Hoat dong');
        RETURN 'Tang 1 goi 1 ngay (DV03)';

    ELSIF p_hang <= 20 THEN
        SELECT mavp, tenvp INTO v_mavp, v_tenvp FROM fn_tim_qua_tang();
        IF v_mavp IS NOT NULL THEN
            UPDATE vatpham SET soluong = soluong - 1 WHERE mavp = v_mavp;
            RETURN 'Tang 1 ' || v_tenvp;
        ELSE
            RETURN 'Kho da het qua tang';
        END IF;
    END IF;
    RETURN '';
END;
$$;


--
-- Name: fn_tang_qua_rankup(character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_tang_qua_rankup(p_makh character varying, p_rankcu character varying, p_rankmoi character varying) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE v_mavp VARCHAR(6); v_tenvp VARCHAR(20);
BEGIN
    IF p_rankmoi = p_rankcu THEN RETURN ''; END IF;

    SELECT mavp, tenvp INTO v_mavp, v_tenvp FROM fn_tim_qua_tang();
    IF v_mavp IS NULL THEN RETURN 'Kho da het qua tang'; END IF;

    UPDATE vatpham SET soluong = soluong - 1 WHERE mavp = v_mavp;
    RETURN 'QUA TANG    : ' || v_tenvp || ' (da tru kho)';
END;
$$;


--
-- Name: fn_tao_order(character varying, character varying, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_tao_order(p_maorder character varying, p_makh character varying, p_hoten character varying, p_madv character varying, p_maghe character varying DEFAULT NULL::character varying, p_mapr character varying DEFAULT NULL::character varying, p_sdt character varying DEFAULT NULL::character varying) RETURNS text
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_madv IN ('DV03', 'DV04') THEN
        RAISE EXCEPTION 'DV03/DV04 la goi hoat dong. Hay dang ky hoac gia han trong tab Goi, khong tao trong Orders.';
    END IF;

    PERFORM fn_upsert_khachhang(p_makh, p_hoten, p_sdt);
    VALUES (p_maorder,p_makh,p_madv,p_maghe,p_mapr,'Dang dung',NOW(),NOW());
    PERFORM fn_dat_cho(p_maghe, p_mapr);  -- thêm dòng này
    RETURN 'Tao order ' || p_maorder || ' thanh cong cho KH ' || p_makh;
END;
$$;


--
-- Name: fn_tao_vatpham(character varying, character varying, numeric, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_tao_vatpham(p_mavp character varying, p_tenvp character varying, p_giatien numeric, p_soluong integer DEFAULT 0) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_makho varchar(6);
BEGIN
    IF p_mavp IS NULL OR trim(p_mavp) = '' THEN
        RAISE EXCEPTION 'Ma vat pham khong duoc de trong.';
    END IF;
    IF p_tenvp IS NULL OR trim(p_tenvp) = '' THEN
        RAISE EXCEPTION 'Ten vat pham khong duoc de trong.';
    END IF;
    IF p_giatien IS NULL OR p_giatien <= 0 THEN
        RAISE EXCEPTION 'Gia tien phai lon hon 0.';
    END IF;
    IF p_soluong IS NULL OR p_soluong < 0 THEN
        RAISE EXCEPTION 'So luong ban dau khong duoc am.';
    END IF;

    VALUES (trim(p_mavp), trim(p_tenvp), p_giatien::money, NULL, p_soluong)
    RETURNING makho INTO v_makho;

    RETURN 'Tao vat pham ' || trim(p_mavp) || ' tai kho ' || v_makho;
END;
$$;


--
-- Name: fn_thanh_toan(character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_thanh_toan(p_maorder character varying, p_manv character varying, p_hinhthuctt character varying) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_makh VARCHAR(6); v_madv VARCHAR(6); v_status VARCHAR(20);
    v_gia_dv NUMERIC; v_tong_vp NUMERIC; v_tong_hd NUMERIC;
    v_discount NUMERIC; v_rank VARCHAR(10);
    v_co_goi BOOLEAN; v_thongbao TEXT;
BEGIN
    SELECT makh, madv, status INTO v_makh, v_madv, v_status
    FROM orders WHERE maorder = p_maorder;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Order % khong ton tai.', p_maorder;
    END IF;
    IF v_status != 'Dang dung' THEN
        RAISE EXCEPTION 'Order khong o trang thai Dang dung (hien tai: %).', v_status;
    END IF;

    SELECT giagoi::NUMERIC INTO v_gia_dv FROM dichvu WHERE madv = v_madv;
    SELECT COALESCE(SUM(vp.giatien::NUMERIC * ct.soluong), 0) INTO v_tong_vp
    FROM chitietorder ct JOIN vatpham vp ON ct.mavp = vp.mavp
    WHERE ct.maorder = p_maorder;

    SELECT rank INTO v_rank FROM khachhang WHERE makh = v_makh;
    v_discount := fn_tinh_discount(v_makh);
    v_co_goi   := fn_kiem_tra_goi(v_makh);

    v_tong_hd := CASE WHEN v_co_goi THEN v_tong_vp ELSE v_gia_dv + v_tong_vp END;
    v_tong_hd := ROUND(v_tong_hd * (1 - v_discount));

    UPDATE orders SET
        status     = 'Hoan thanh',
        gioketthuc = NOW() + INTERVAL '1 second',
        thoigiantt = NOW(),
        hinhthuctt = p_hinhthuctt,
        manv       = p_manv
    WHERE maorder = p_maorder;

    v_thongbao := fn_tichdiem_capnhat_rank(v_makh, v_tong_hd);

    RETURN '===== THANH TOAN =====' || chr(10) ||
        'Order    : ' || p_maorder || chr(10) ||
        'Gia DV   : ' || v_gia_dv ||
            CASE WHEN v_co_goi THEN ' (mien phi)' ELSE '' END || chr(10) ||
        'Tong VP  : ' || v_tong_vp || chr(10) ||
        'Discount : ' || (v_discount*100)::INT || '% (rank ' || v_rank || ')' || chr(10) ||
        'Tong HD  : ' || v_tong_hd || chr(10) ||
        v_thongbao;
END;
$$;


--
-- Name: fn_them_chitietorder(character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_them_chitietorder(p_maorder character varying, p_mavp character varying, p_soluong integer DEFAULT 1) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE v_status VARCHAR(20); v_tenvp VARCHAR(20);
BEGIN
    IF p_soluong <= 0 THEN
        RAISE EXCEPTION 'So luong vat pham phai lon hon 0 (nhan vao: %).', p_soluong;
    END IF;

    SELECT status INTO v_status FROM orders WHERE maorder = p_maorder;
    IF NOT FOUND THEN RAISE EXCEPTION 'Order % khong ton tai.', p_maorder; END IF;
    IF v_status != 'Dang dung' THEN
        RAISE EXCEPTION 'Khong the them vat pham: order dang %.', v_status;
    END IF;

    v_tenvp := fn_kiem_tra_stock(p_mavp, p_soluong);

    VALUES (p_maorder, p_mavp, p_soluong)
    ON CONFLICT (maorder, mavp)
    DO UPDATE SET soluong = chitietorder.soluong + p_soluong;

    UPDATE vatpham SET soluong = soluong - p_soluong WHERE mavp = p_mavp;

    RETURN 'Da them ' || p_soluong || ' x ' || v_tenvp || ' vao order ' || p_maorder;
END;
$$;


--
-- Name: fn_thongke_khunggio(date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_thongke_khunggio(p_tungay date, p_denngay date) RETURNS TABLE(khung_gio text, luot_su_dung bigint, doanh_thu numeric, xep_hang_luot bigint, xep_hang_doanh_thu bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    WITH khunggio AS (
        SELECT
            h AS gio_bd,
            h + 2 AS gio_kt,
            LPAD(h::TEXT, 2, '0') || 'h-' || LPAD((h+2)::TEXT, 2, '0') || 'h' AS ten_khung
        FROM generate_series(0, 22, 2) h
    ),
    thongke AS (
        SELECT
            kg.ten_khung,
            COUNT(DISTINCT o.maorder) AS luot_su_dung,
            COALESCE(SUM(
                CASE WHEN o.maorder IS NOT NULL THEN
                    COALESCE(dv.giagoi::NUMERIC, 0) + COALESCE((
                        SELECT SUM(ct.soluong * vp.giatien::NUMERIC)
                        FROM chitietorder ct JOIN vatpham vp ON ct.mavp = vp.mavp
                        WHERE ct.maorder = o.maorder
                    ), 0)
                ELSE 0 END
            ), 0) AS doanh_thu
        FROM khunggio kg
        LEFT JOIN orders o
            ON o.giobatdau::DATE BETWEEN p_tungay AND p_denngay
            AND o.giobatdau::TIME < make_time(kg.gio_kt, 0, 0)
            AND o.gioketthuc::TIME > make_time(kg.gio_bd, 0, 0)
            AND o.status = 'Hoan thanh'
        LEFT JOIN dichvu dv ON dv.madv = o.madv
        GROUP BY kg.ten_khung, kg.gio_bd
    )
    SELECT
        t.ten_khung AS khung_gio,
        t.luot_su_dung,
        t.doanh_thu,
        RANK() OVER (ORDER BY t.luot_su_dung DESC) AS xep_hang_luot,
        RANK() OVER (ORDER BY t.doanh_thu DESC) AS xep_hang_doanh_thu
    FROM thongke t
    ORDER BY t.ten_khung;
END;
$$;


--
-- Name: fn_thongke_nghi_som(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_thongke_nghi_som(p_thang integer, p_nam integer) RETURNS TABLE(ma_nv character varying, ten_nv character varying, so_lan_nghi_som bigint, tong_thoi_gian interval)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT nv.manv, nv.tennv::VARCHAR(50),
        COUNT(cl.ngay)::BIGINT,
        SUM(cl.thoigiannghisom::INTERVAL)
    FROM nhanvien nv
    JOIN dilam dl ON nv.manv = dl.manv
    JOIN calam cl ON dl.ngay = cl.ngay AND dl.cathu = cl.cathu
    WHERE EXTRACT(MONTH FROM cl.ngay) = p_thang
      AND EXTRACT(YEAR  FROM cl.ngay) = p_nam
      AND cl.nghisom = TRUE
    GROUP BY nv.manv, nv.tennv
    ORDER BY so_lan_nghi_som DESC, tong_thoi_gian DESC;
END;
$$;


--
-- Name: fn_tichdiem_capnhat_rank(text, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_tichdiem_capnhat_rank(p_makh text, p_tonghoadon numeric) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_diem INT; v_diemmoi INT; v_rankcu VARCHAR; v_rankmoi VARCHAR; v_thongbao TEXT;
BEGIN
    IF p_tonghoadon <= 0 THEN
        RAISE EXCEPTION 'Tong hoa don phai lon hon 0 (nhan vao: %).', p_tonghoadon;
    END IF;
    IF NOT EXISTS (SELECT 1 FROM khachhang WHERE makh = p_makh) THEN
        RAISE EXCEPTION 'Khach hang % khong ton tai.', p_makh;
    END IF;

    v_diem := FLOOR(p_tonghoadon / 1000);
    SELECT rank INTO v_rankcu FROM khachhang WHERE makh = p_makh;

    UPDATE khachhang SET diemtichluy = diemtichluy + v_diem
    WHERE makh = p_makh RETURNING diemtichluy INTO v_diemmoi;

    v_rankmoi := fn_tinh_rank(v_diemmoi);
    UPDATE khachhang SET rank = v_rankmoi WHERE makh = p_makh;

    v_thongbao :=
        '=============================' || chr(10) ||
        'Khach hang  : ' || p_makh || chr(10) ||
        'Hoa don     : ' || p_tonghoadon || ' dong' || chr(10) ||
        'Diem cong   : ' || v_diem || ' diem' || chr(10) ||
        'Tong diem   : ' || v_diemmoi || ' diem' || chr(10) ||
        CASE WHEN v_rankmoi != v_rankcu
             THEN 'RANK UP: ' || v_rankcu || ' -> ' || v_rankmoi
             ELSE 'Rank        : ' || v_rankmoi || ' (giu nguyen)'
        END || chr(10) || '=====';

    v_thongbao := v_thongbao || chr(10) ||
        fn_tang_qua_rankup(p_makh::VARCHAR(6), v_rankcu, v_rankmoi);

    RETURN v_thongbao;
END;
$$;


--
-- Name: fn_tim_qua_tang(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_tim_qua_tang() RETURNS TABLE(mavp character varying, tenvp character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT vp.mavp, vp.tenvp
  FROM vatpham vp
  LEFT JOIN (
    SELECT ct.mavp, SUM(ct.soluong) AS tong_ban
    FROM chitietorder ct
    JOIN orders o ON ct.maorder = o.maorder
    WHERE o.status = 'Hoan thanh'
    GROUP BY ct.mavp
  ) sold ON vp.mavp = sold.mavp
  WHERE vp.soluong > 0
  ORDER BY COALESCE(sold.tong_ban, 0) ASC
  LIMIT 1;
END;
$$;


--
-- Name: fn_tinh_discount(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_tinh_discount(p_makh character varying) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE v_rank VARCHAR(10);
BEGIN
    SELECT rank INTO v_rank FROM khachhang WHERE makh = p_makh;
    RETURN CASE v_rank
        WHEN 'Bac'       THEN 0.02
        WHEN 'Vang'      THEN 0.05
        WHEN 'Kim cuong' THEN 0.10
        ELSE 0
    END;
END;
$$;


--
-- Name: fn_tinh_rank(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_tinh_rank(p_diem integer) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN CASE
        WHEN p_diem >= 2500 THEN 'Kim cuong'
        WHEN p_diem >= 1000 THEN 'Vang'
        WHEN p_diem >= 500  THEN 'Bac'
        ELSE 'Dong'
    END;
END;
$$;


--
-- Name: fn_tra_cho(character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_tra_cho(p_maghe character varying, p_mapr character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE v_mapc VARCHAR(6);
BEGIN
    IF p_maghe IS NOT NULL THEN
        SELECT mapc INTO v_mapc FROM ghe WHERE maghe = p_maghe;
        UPDATE phongchung SET soghetrong = soghetrong + 1 WHERE mapc = v_mapc;
        UPDATE phongchung SET status = 'Chua day' WHERE mapc = v_mapc AND soghetrong > 0;
    END IF;
    IF p_mapr IS NOT NULL THEN
        UPDATE phongrieng SET status = 'Chua day' WHERE mapr = p_mapr;
    END IF;
END;
$$;


--
-- Name: fn_upsert_khachhang(character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_upsert_khachhang(p_makh character varying, p_hoten character varying, p_sdt character varying DEFAULT NULL::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    VALUES (p_makh, p_hoten, p_sdt)
    ON CONFLICT (makh) DO NOTHING;
END;
$$;


--
-- Name: fn_vatpham_kho_co_dinh(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_vatpham_kho_co_dinh() RETURNS trigger
    LANGUAGE plpgsql
    AS $$ DECLARE v_makho varchar(6); BEGIN IF TG_OP = 'INSERT' THEN IF NEW.makho IS NOT NULL THEN RAISE EXCEPTION 'Khong duoc tu chon kho cho vat pham moi %. Hay de database tu phan bo.', NEW.mavp; END IF; SELECT k.makho INTO v_makho FROM kho k LEFT JOIN vatpham v ON v.makho = k.makho GROUP BY k.makho ORDER BY COUNT(v.mavp), k.makho LIMIT 1; IF v_makho IS NULL THEN RAISE EXCEPTION 'Khong co kho de gan cho vat pham moi.'; END IF; NEW.makho := v_makho; ELSIF NEW.makho IS DISTINCT FROM OLD.makho THEN RAISE EXCEPTION 'Vat pham % da thuoc kho % va khong duoc chuyen sang kho %.', OLD.mavp, OLD.makho, NEW.makho; END IF; RETURN NEW; END; $$;


--
-- Name: fn_vinh_danh_thang(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_vinh_danh_thang(p_thang integer, p_nam integer) RETURNS TABLE(hang integer, makh character varying, hoten character varying, diem integer, uu_dai text)
    LANGUAGE plpgsql
    AS $$
DECLARE r RECORD;
BEGIN
    FOR r IN (
        SELECT ROW_NUMBER() OVER (ORDER BY diemtichluy DESC)::INT AS h,
               k.makh, k.hoten, k.diemtichluy
        FROM khachhang k LIMIT 20
    ) LOOP
        hang   := r.h;
        makh   := r.makh;
        hoten  := r.hoten;
        diem   := r.diemtichluy;
        uu_dai := fn_phat_thuong_vinh_danh(r.makh, r.h);
        RETURN NEXT;
    END LOOP;
END;
$$;


--
-- Name: fn_xep_cho(integer, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_xep_cho(p_so_nguoi integer, p_loai character varying) RETURNS TABLE(loai_cho text, ma character varying, thong_tin text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_loai = 'rieng' THEN
        RETURN QUERY SELECT * FROM fn_xep_cho_rieng(p_so_nguoi);
        IF NOT FOUND THEN
            RAISE NOTICE 'Khong con phong rieng. Chuyen sang phong chung.';
            RETURN QUERY SELECT * FROM fn_xep_cho_chung(p_so_nguoi);
        END IF;
    ELSIF p_loai = 'chung' THEN
        RETURN QUERY SELECT * FROM fn_xep_cho_chung(p_so_nguoi);
    END IF;
END;
$$;


--
-- Name: fn_xep_cho_chung(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_xep_cho_chung(p_so_nguoi integer) RETURNS TABLE(loai_cho text, ma character varying, thong_tin text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT ('Ghe tai phong ' || g.mapc)::TEXT, g.maghe,
        ('Phong ' || g.mapc || ' con ' || pc.soghetrong || ' ghe trong')::TEXT
    FROM ghe g JOIN phongchung pc ON g.mapc = pc.mapc
    WHERE pc.status = 'Chua day'
      AND NOT EXISTS (SELECT 1 FROM orders o
          WHERE o.maghe = g.maghe AND o.status IN ('Dat truoc','Dang dung'))
      AND NOT EXISTS (
          SELECT 1 FROM orders o JOIN goihoatdong gh ON o.makh = gh.makh
          WHERE o.maghe = g.maghe AND o.status = 'Dang dung'
            AND gh.status = 'Hoat dong' AND gh.ngayketthuc >= CURRENT_DATE)
    LIMIT p_so_nguoi;
END;
$$;


--
-- Name: fn_xep_cho_rieng(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_xep_cho_rieng(p_so_nguoi integer) RETURNS TABLE(loai_cho text, ma character varying, thong_tin text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 'Phong rieng'::TEXT, pr.mapr,
        ('Toi da ' || pr.songuoitoida || ' nguoi | He so gia: x' || pr.hesogia)::TEXT
    FROM phongrieng pr
    WHERE pr.status = 'Chua day'
      AND pr.songuoitoida >= p_so_nguoi
      AND NOT EXISTS (
          SELECT 1 FROM orders o JOIN goihoatdong g ON o.makh = g.makh
          WHERE o.mapr = pr.mapr AND o.status IN ('Dat truoc','Dang dung')
            AND g.status = 'Hoat dong' AND g.ngayketthuc >= CURRENT_DATE)
    ORDER BY pr.songuoitoida ASC;
END;
$$;


--
-- Name: sp_capnhat_trangthai_goi(); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.sp_capnhat_trangthai_goi()
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE goihoatdong SET status = 'Hoat dong'
    WHERE status = 'Khong hoat dong'
      AND CURRENT_DATE BETWEEN ngaybatdau AND ngayketthuc;

    UPDATE goihoatdong SET status = 'Khong hoat dong'
    WHERE status = 'Hoat dong'
      AND ngayketthuc < CURRENT_DATE;
END;
$$;


--
-- Name: sp_dangky_goi(character varying, character varying, date); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.sp_dangky_goi(IN p_makh character varying, IN p_madv character varying, IN p_ngaybatdau date)
    LANGUAGE plpgsql
    AS $$
DECLARE v_ngayketthuc DATE;
BEGIN
    IF p_madv NOT IN ('DV03','DV04') THEN
        RAISE EXCEPTION 'Chi DV03 va DV04 duoc phep dang ky goi hoat dong';
    END IF;

    v_ngayketthuc := CASE
        WHEN p_madv = 'DV03' THEN p_ngaybatdau + 1
        WHEN p_madv = 'DV04' THEN p_ngaybatdau + 7
    END;

    IF EXISTS (
        SELECT 1 FROM goihoatdong
        WHERE makh = p_makh
          AND p_ngaybatdau  <= ngayketthuc
          AND v_ngayketthuc >= ngaybatdau
    ) THEN
        RAISE EXCEPTION 'Khach hang da co goi trong khoang thoi gian nay';
    END IF;

    VALUES (p_makh, p_madv, p_ngaybatdau, v_ngayketthuc,
        CASE WHEN p_ngaybatdau = CURRENT_DATE THEN 'Hoat dong' ELSE 'Khong hoat dong' END);

    RAISE NOTICE 'Dang ky goi thanh cong';
END;
$$;


--
-- Name: sp_doi_cheo_ca(character varying, date, character varying, character varying, date, character varying); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.sp_doi_cheo_ca(IN p_manv1 character varying, IN p_ngay1 date, IN p_cathu1 character varying, IN p_manv2 character varying, IN p_ngay2 date, IN p_cathu2 character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- FIX: chặn đổi ca với chính mình cùng slot
    IF p_manv1 = p_manv2 AND p_ngay1 = p_ngay2 AND p_cathu1 = p_cathu2 THEN
        RAISE EXCEPTION 'Khong the doi ca voi chinh minh (cung NV, cung ngay, cung ca).';
    END IF;

    -- Kiểm tra NV1 có ca đó không
    IF NOT EXISTS (SELECT 1 FROM dilam WHERE manv = p_manv1 AND ngay = p_ngay1 AND cathu = p_cathu1) THEN
        RAISE EXCEPTION 'Nhan vien % khong co ca % ngay %.', p_manv1, p_cathu1, p_ngay1;
    END IF;

    -- Kiểm tra NV2 có ca đó không
    IF NOT EXISTS (SELECT 1 FROM dilam WHERE manv = p_manv2 AND ngay = p_ngay2 AND cathu = p_cathu2) THEN
        RAISE EXCEPTION 'Nhan vien % khong co ca % ngay %.', p_manv2, p_cathu2, p_ngay2;
    END IF;

    -- Kiểm tra xung đột: NV2 sắp nhận ca1
    IF p_manv1 != p_manv2 AND EXISTS (
        SELECT 1 FROM dilam WHERE manv = p_manv2 AND ngay = p_ngay1 AND cathu = p_cathu1
    ) THEN
        RAISE EXCEPTION 'Nhan vien % da co ca % ngay % roi, khong the nhan them.', p_manv2, p_cathu1, p_ngay1;
    END IF;

    -- Kiểm tra xung đột: NV1 sắp nhận ca2
    IF p_manv1 != p_manv2 AND EXISTS (
        SELECT 1 FROM dilam WHERE manv = p_manv1 AND ngay = p_ngay2 AND cathu = p_cathu2
    ) THEN
        RAISE EXCEPTION 'Nhan vien % da co ca % ngay % roi, khong the nhan them.', p_manv1, p_cathu2, p_ngay2;
    END IF;

    -- Dùng DELETE + INSERT để tránh conflict khóa chính
    DELETE FROM dilam
    WHERE (manv = p_manv1 AND ngay = p_ngay1 AND cathu = p_cathu1)
       OR (manv = p_manv2 AND ngay = p_ngay2 AND cathu = p_cathu2);


    RAISE NOTICE 'Doi ca thanh cong: % (% %) <-> % (% %)',
        p_manv1, p_ngay1, p_cathu1, p_manv2, p_ngay2, p_cathu2;
END;
$$;


--
-- Name: sp_giahan_goi(integer, integer); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.sp_giahan_goi(IN p_id integer, IN p_songay integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE goihoatdong
    SET ngayketthuc = ngayketthuc + p_songay
    WHERE id = p_id AND status = 'Hoat dong';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Khong tim thay goi dang hoat dong voi ID: %', p_id;
    END IF;
END;
$$;


--
-- Name: sp_huy_goi(integer); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.sp_huy_goi(IN p_id integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE goihoatdong SET status = 'Khong hoat dong'
    WHERE id = p_id AND status = 'Hoat dong';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Khong tim thay goi hoac goi da khong hoat dong';
    END IF;
END;
$$;


--
-- Name: sp_lam_thay_ca(character varying, character varying, date, character varying); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.sp_lam_thay_ca(IN p_manv_thay character varying, IN p_manv_nghi character varying, IN p_ngay date, IN p_cathu character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Kiểm tra ca cần thay tồn tại
    IF NOT EXISTS (
        SELECT 1 FROM dilam
        WHERE manv = p_manv_nghi AND ngay = p_ngay AND cathu = p_cathu
    ) THEN
        RAISE EXCEPTION 'Nhân viên % không có ca % ngày %', p_manv_nghi, p_cathu, p_ngay;
    END IF;

    -- Kiểm tra NV thay không trùng ca khác cùng ngày ca đó
    IF EXISTS (
        SELECT 1 FROM dilam
        WHERE manv = p_manv_thay AND ngay = p_ngay AND cathu = p_cathu
    ) THEN
        RAISE EXCEPTION 'Nhân viên % đã có ca % ngày % rồi', p_manv_thay, p_cathu, p_ngay;
    END IF;

    -- Cập nhật nhân viên làm thay
    UPDATE dilam SET manv = p_manv_thay
    WHERE manv = p_manv_nghi AND ngay = p_ngay AND cathu = p_cathu;

    RAISE NOTICE '% làm thay % ca % ngày %', p_manv_thay, p_manv_nghi, p_cathu, p_ngay;
END;
$$;


--
-- Name: top_vatpham_thang(integer, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.top_vatpham_thang(p_thang integer, p_nam integer, p_top integer DEFAULT 5) RETURNS TABLE(hang integer, mavp character varying, tenvp character varying, tong_soluong bigint, tong_doanhthu money)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        ROW_NUMBER() OVER (ORDER BY SUM(ct.soluong) DESC)::INT AS hang,
        v.mavp,
        v.tenvp,
        SUM(ct.soluong) AS tong_soluong,
        SUM(ct.soluong * v.giatien) AS tong_doanhthu
    FROM chitietorder ct
    JOIN vatpham v ON v.mavp = ct.mavp
    JOIN orders o ON o.maorder = ct.maorder
    WHERE EXTRACT(MONTH FROM o.thoigiantt) = p_thang
      AND EXTRACT(YEAR FROM o.thoigiantt) = p_nam
      AND o.status = 'Hoan thanh'
    GROUP BY v.mavp, v.tenvp
    ORDER BY tong_soluong DESC
    LIMIT p_top;
END;
$$;


