    madv character varying(6) NOT NULL,
    makh character varying(6) NOT NULL,
    maghe character varying(6),
    mapr character varying(6),
    manv character varying(6),
    thoigiandat timestamp without time zone,
    CONSTRAINT orders_gio_check CHECK (((gioketthuc IS NULL) OR (giobatdau IS NULL) OR (gioketthuc > giobatdau))),
    CONSTRAINT orders_hinhthuctt_check CHECK (((hinhthuctt IS NULL) OR ((hinhthuctt)::text = ANY (ARRAY[('Tien mat'::character varying)::text, ('Chuyen khoan'::character varying)::text, ('The'::character varying)::text])))),
    CONSTRAINT orders_phong_xor_check CHECK ((num_nonnulls(maghe, mapr) = 1)),
    CONSTRAINT orders_status_check CHECK (((status)::text = ANY (ARRAY[('Dat truoc'::character varying)::text, ('Dang dung'::character varying)::text, ('Hoan thanh'::character varying)::text, ('Da huy'::character varying)::text])))
);


