--
-- Name: v_ca_thieu_nhan_vien; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_ca_thieu_nhan_vien AS
 SELECT ngay,
    cathu,
    status
   FROM public.calam cl
  WHERE (((status)::text = 'Chua co nguoi'::text) AND ((ngay >= CURRENT_DATE) AND (ngay <= (CURRENT_DATE + '7 days'::interval))))
  ORDER BY ngay, cathu;


--
-- Name: v_lap_day_phong_chung; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_lap_day_phong_chung AS
 SELECT mapc,
    status,
    soghetrong
   FROM public.phongchung pc
  WHERE ((soghetrong = 0) AND ((status)::text = 'Day'::text));


--
-- Name: v_order_chua_thanh_toan; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_order_chua_thanh_toan AS
 SELECT o.maorder,
    o.giobatdau,
    o.gioketthuc,
    o.status,
    dv.tendv,
    kh.hoten AS tenkhachhang,
    kh.sdt
   FROM ((public.orders o
     JOIN public.dichvu dv ON (((dv.madv)::text = (o.madv)::text)))
     JOIN public.khachhang kh ON (((kh.makh)::text = (o.makh)::text)))
  WHERE (o.hinhthuctt IS NULL)
  ORDER BY o.giobatdau;


--
-- Name: v_phong_ghe_trong; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.v_phong_ghe_trong AS
 SELECT pc.mapc,
    pc.soghetrong,
    count(g.maghe) AS tong_ghe
   FROM (public.phongchung pc
     LEFT JOIN public.ghe g ON (((g.mapc)::text = (pc.mapc)::text)))
  WHERE (((pc.status)::text = 'Chua day'::text) AND (pc.soghetrong > 0))
  GROUP BY pc.mapc, pc.soghetrong;


